import pytest
import requests

def test_limit_above_200_returns_422(auth_token_fixture, base_url):
    headers = {"Authorization": f"Bearer {auth_token_fixture}"}
    response = requests.get(
        f"{base_url}/api/employees",
        headers=headers,
        params={"limit": 201}
    )
    assert response.status_code == 422, (
        f"Expected 422 for limit=201, got {response.status_code}"
    )
    body = response.json()
    has_error = "detail" in body or "error" in body
    assert has_error, "Response body must contain 'detail' or 'error' key"

import pytest
import requests

def test_limit_at_200_boundary_returns_200_ok(auth_token_fixture, base_url):
    headers = {"Authorization": f"Bearer {auth_token_fixture}"}
    response = requests.get(
        f"{base_url}/api/employees",
        headers=headers,
        params={"limit": 200}
    )
    assert response.status_code == 200, (
        f"Expected 200 for limit=200 (boundary), got {response.status_code}"
    )
    body = response.json()
    assert "data" in body, "Response must contain 'data' key"
    assert len(body["data"]) <= 200, (
        f"Expected at most 200 items, got {len(body['data'])}"
    )

